// Extract and normalise the incoming webhook body.
// Sets routing flags used by the downstream IF nodes.

const webhookData = $input.first().json;
const body = webhookData.body || webhookData;

const url      = (body.url      || '').trim();
const note     = (body.note     || '').trim();
const content  = (body.content  || '').trim();
const filename = (body.filename || '').trim();

// Pre-provided content: file upload or pasted text sent directly in the payload
const isPreProvided = content.length >= 200;

// YouTube URL — only relevant when content is not pre-provided
const isYoutube = !isPreProvided && /youtube\.com\/watch|youtu\.be\//i.test(url);

return [{ json: { url, note, content, filename, isPreProvided, isYoutube } }];

// Content was supplied directly (file upload or pasted text). Pass it through.
const d = $input.first().json;
const content = d.content.trim();
return [{ json: { url: d.url, note: d.note, content, contentLength: content.length, jinaOk: true, errorMessage: null } }];

// Format the Supadata transcript response.
const routeData    = $('Route Input').first().json;
const supaResponse = $input.first().json;
const url  = routeData.url;
const note = routeData.note;

let content = '';
let jinaOk  = false;
let errorMessage = null;

if (supaResponse.error) {
  errorMessage = 'Supadata error: ' + (typeof supaResponse.error === 'string' ? supaResponse.error : JSON.stringify(supaResponse.error).substring(0, 200));
} else if (supaResponse.content && typeof supaResponse.content === 'string' && supaResponse.content.trim().length >= 200) {
  content = supaResponse.content.trim();
  jinaOk  = true;
} else {
  errorMessage = 'Supadata returned no usable transcript. The video may have no captions, be private, or be age-restricted. Response: ' + JSON.stringify(supaResponse).substring(0, 200);
}

return [{ json: { url, note, content, contentLength: content.length, jinaOk, errorMessage } }];

// Format the Jina Reader plain-text response.
const routeData    = $('Route Input').first().json;
const jinaResponse = $input.first().json;
const url  = routeData.url;
const note = routeData.note;

let content = '';
let jinaOk  = false;
let errorMessage = null;

if (jinaResponse.error) {
  errorMessage = 'Jina Reader error: ' + JSON.stringify(jinaResponse.error).substring(0, 200);
} else {
  // n8n HTTP Request wraps plain-text responses as { data: '...' }
  const rawBody = jinaResponse.data || jinaResponse.body || jinaResponse.content || '';
  content = (typeof rawBody === 'string' ? rawBody : JSON.stringify(rawBody)).trim();

  if (content.length >= 200) {
    jinaOk = true;
  } else {
    errorMessage = 'Jina Reader returned too little content (' + content.length + ' chars). The URL may be paywalled, JS-rendered, or invalid.';
  }
}

return [{ json: { url, note, content, contentLength: content.length, jinaOk, errorMessage } }];

// Build the Groq Call 1 request body.

const SYSTEM_PROMPT = [
  'You are a research librarian assistant. Your job is to analyze content and return structured metadata as JSON.',
  '',
  'You MUST ALWAYS return a JSON object — no matter what the content is, no matter how little there is.',
  'Even if the content is a webpage stub, a video page, or nearly empty, return your best attempt.',
  'NEVER respond with plain text. NEVER say you cannot complete the task. ALWAYS return JSON.',
  '',
  'Return a single JSON object with EXACTLY these fields and no others:',
  '{',
  '  "title": "<string — extracted or inferred title>",',
  '  "source_type": "<one of: Article | PDF | Podcast | Video | Report | Other>",',
  '  "summary": "<string — 2 to 3 paragraphs of plain text, no bullet points, no markdown>",',
  '  "key_claims": ["<string>", "<string>", "<string>"],',
  '  "tags": ["<tag>", "<tag>", "<tag>"]',
  '}',
  '',
  'Rules:',
  '- title: Use the content\'s own title if present. Infer a descriptive title if none is given.',
  '- source_type: Choose the closest match. If the text reads like a spoken transcript, set to Podcast or Video.',
  '- summary: Plain prose only — no bullet points, no markdown, no newlines within the value. Two to three sentences minimum. Write for an intelligent professional researcher.',
  '- key_claims: Array of 3 to 5 strings. Each is one specific fact or assertion.',
  '- tags: Array of 5 to 10 tags, lowercase and hyphenated (e.g. neural-networks, llm-training, transformer-architecture). Be specific to the content domain.',
  '',
  'JSON FORMATTING RULES — these are absolute:',
  '- All string values must be on a single line — no literal newlines inside any string value.',
  '- No trailing commas.',
  '- No comments.',
  '- The response must begin with { and end with } and contain nothing else.',
  '- No markdown code fences, no preamble, no explanation outside the JSON object.'
].join('\n');

const url     = $json.url || '';
const note    = $json.note || '';
const content = ($json.content || '').substring(0, 6000);

const userMessage = 'Analyze the following article content and return the JSON metadata object.\n\nSource URL: ' + url + '\n\nArticle content:\n' + content;

const groqBody = JSON.stringify({
  model: 'llama-3.1-8b-instant',
  temperature: 0.3,
  max_tokens: 2000,
  messages: [
    { role: 'system', content: SYSTEM_PROMPT },
    { role: 'user',   content: userMessage }
  ]
});

return [{
  json: {
    url,
    note,
    content: $json.content || '',
    contentLength: $json.contentLength || 0,
    groqBody
  }
}];

// Parse Groq Call 1 response and validate required fields.

function sanitizeJson(str) {
  let result = '';
  let inString = false;
  let escaped  = false;
  for (let i = 0; i < str.length; i++) {
    const ch   = str[i];
    const code = str.charCodeAt(i);
    if (escaped) { result += ch; escaped = false; continue; }
    if (ch === '\\') { result += ch; escaped = true; continue; }
    if (ch === '"')  { inString = !inString; result += ch; continue; }
    if (inString && code < 32) {
      if      (code === 10) result += '\\n';
      else if (code === 13) result += '\\r';
      else if (code ===  9) result += '\\t';
      else result += '\\u' + code.toString(16).padStart(4, '0');
      continue;
    }
    result += ch;
  }
  return result;
}

const buildGroqData = $('Build Groq Request').first().json;
const url  = buildGroqData.url  || '';
const note = buildGroqData.note || '';
const groqResponse = $input.first().json;

if (groqResponse.error) {
  return [{ json: { groqOk: false, url, note, errorMessage: 'Groq API error: ' + (groqResponse.error.message || JSON.stringify(groqResponse.error)) } }];
}

let rawContent = '';
try {
  rawContent = groqResponse.choices[0].message.content;
} catch (e) {
  return [{ json: { groqOk: false, url, note, errorMessage: 'Unexpected Groq response shape: ' + JSON.stringify(groqResponse).substring(0, 500) } }];
}

let cleaned = rawContent.trim();
if (cleaned.startsWith('```')) {
  cleaned = cleaned.replace(/^```[a-z]*\n?/i, '').replace(/```$/, '').trim();
}

const start = cleaned.indexOf('{');
const end   = cleaned.lastIndexOf('}');
if (start === -1 || end === -1) {
  return [{ json: { groqOk: false, url, note, rawGroqContent: cleaned.substring(0, 500), errorMessage: 'No JSON object found in Groq response' } }];
}
cleaned = cleaned.substring(start, end + 1);

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e1) {
  try {
    parsed = JSON.parse(sanitizeJson(cleaned));
  } catch (e2) {
    return [{ json: { groqOk: false, url, note, rawGroqContent: cleaned.substring(0, 500), errorMessage: 'Groq returned malformed JSON: ' + e2.message } }];
  }
}

const required = ['title', 'source_type', 'summary', 'key_claims', 'tags'];
const missing  = required.filter(f => !parsed[f]);
if (missing.length > 0) {
  return [{ json: { groqOk: false, url, note, rawGroqContent: cleaned.substring(0, 500), errorMessage: 'Groq JSON missing fields: ' + missing.join(', ') } }];
}

const validSourceTypes = ['Article', 'PDF', 'Podcast', 'Video', 'Report', 'Other'];
if (!validSourceTypes.includes(parsed.source_type)) parsed.source_type = 'Other';
if (!Array.isArray(parsed.key_claims)) parsed.key_claims = [String(parsed.key_claims)];
if (!Array.isArray(parsed.tags))       parsed.tags       = [String(parsed.tags)];

const keyClaimsText = parsed.key_claims.map(c => '\u2022 ' + c).join('\n');
const today = new Date().toISOString().split('T')[0];

return [{ json: { groqOk: true, url, note, title: parsed.title, source_type: parsed.source_type, summary: parsed.summary, key_claims: keyClaimsText, tags: parsed.tags, date_added: today } }];

