// Check Airtable response and extract the created record ID.

const groqData         = $('Parse Groq Response').first().json;
const airtableResponse = $input.first().json;

if (airtableResponse.error) {
  return [{ json: {
    airtableOk: false,
    url:   groqData.url,
    title: groqData.title,
    errorMessage: 'Airtable API error: ' + (airtableResponse.error.message || JSON.stringify(airtableResponse.error))
  }}];
}

if (!airtableResponse.id) {
  return [{ json: {
    airtableOk: false,
    url:   groqData.url,
    title: groqData.title,
    errorMessage: 'Airtable response missing record ID: ' + JSON.stringify(airtableResponse).substring(0, 300)
  }}];
}

return [{ json: {
  airtableOk: true,
  recordId:    airtableResponse.id,
  url:         groqData.url,
  title:       groqData.title,
  summary:     groqData.summary,
  tags:        groqData.tags,
  source_type: groqData.source_type
}}];

// Build the Phase 2 Groq request — find articles related to the newly saved one.

const SYSTEM_PROMPT = 'You are a research librarian assistant. Your job is to identify meaningful connections between a newly saved article and a list of previously saved research items.\n\nYou will receive:\n1. A new article\'s tags and summary\n2. A list of up to 50 previously saved articles with their titles, URLs, and tags\n\nReturn a JSON object with EXACTLY this shape:\n{\n  "related": [\n    { "title": "<string>", "url": "<string>", "reason": "<string — one sentence>" }\n  ]\n}\n\nRules:\n- Select the top 3 most meaningfully related prior articles. If fewer than 3 are genuinely related, return fewer — do not force weak connections.\n- A connection is meaningful if the prior article shares at least 2 tags, addresses the same underlying question, or directly supports or contradicts the new article\'s key argument.\n- The reason field must be a single sentence explaining the specific connection — not generic phrasing like \'both discuss AI\'.\n- Do not include the new article itself in the results.\n- If no prior articles are meaningfully related, return { "related": [] }.\n\nCRITICAL: Return only the raw JSON object. No markdown code fences, no preamble, no explanation. The response must begin with { and end with }.';

const newArticle      = $('Parse Groq Response').first().json;
const airtableData    = $('Check Airtable Response').first().json;
const priorResponse   = $input.first().json;

const newUrl     = airtableData.url || '';
const newTags    = Array.isArray(newArticle.tags) ? newArticle.tags.join(', ') : (newArticle.tags || '');
const newSummary = newArticle.summary || '';

// Extract prior records from Airtable list response, strip the newly created one
const records = (priorResponse.records || [])
  .filter(r => r.fields && r.fields.title && r.fields.url !== newUrl)
  .slice(0, 50)
  .map(r => ({
    title: r.fields.title || '',
    url:   r.fields.url   || '',
    tags:  Array.isArray(r.fields.tags) ? r.fields.tags : []
  }));

// No prior records yet — skip Groq and go straight to Respond Success
if (records.length === 0) {
  return [{ json: { skipGroq2: true, recordId: airtableData.recordId } }];
}

const userMessage = 'New article:\nTags: ' + newTags + '\nSummary: ' + newSummary + '\n\nPreviously saved articles:\n' + JSON.stringify(records, null, 2);

const groq2Body = JSON.stringify({
  model: 'llama-3.1-8b-instant',
  temperature: 0.3,
  max_tokens: 800,
  messages: [
    { role: 'system', content: SYSTEM_PROMPT },
    { role: 'user',   content: userMessage }
  ]
});

return [{ json: { skipGroq2: false, groq2Body, recordId: airtableData.recordId } }];

// Parse Phase 2 Groq response — extract related items.
// Failures here are non-fatal: the record is already saved.

function sanitizeJson(str) {
  let result = '';
  let inString = false;
  let escaped  = false;
  for (let i = 0; i < str.length; i++) {
    const ch   = str[i];
    const code = str.charCodeAt(i);
    if (escaped) { result += ch; escaped = false; continue; }
    if (ch === '\\') { result += ch; escaped = true; continue; }
    if (ch === '"')  { inString = !inString; result += ch; continue; }
    if (inString && code < 32) {
      if      (code === 10) result += '\\n';
      else if (code === 13) result += '\\r';
      else if (code ===  9) result += '\\t';
      else result += '\\u' + code.toString(16).padStart(4, '0');
      continue;
    }
    result += ch;
  }
  return result;
}

const buildData    = $('Build Groq 2 Request').first().json;
const groqResponse = $input.first().json;
const recordId     = buildData.recordId;

// Groq API error — skip update, still respond success
if (groqResponse.error) {
  return [{ json: { hasRelated: false, recordId, relatedText: '' } }];
}

let rawContent = '';
try {
  rawContent = groqResponse.choices[0].message.content;
} catch (e) {
  return [{ json: { hasRelated: false, recordId, relatedText: '' } }];
}

let cleaned = rawContent.trim();
if (cleaned.startsWith('```')) {
  cleaned = cleaned.replace(/^```[a-z]*\n?/i, '').replace(/```$/, '').trim();
}

const start = cleaned.indexOf('{');
const end   = cleaned.lastIndexOf('}');
if (start === -1 || end === -1) {
  return [{ json: { hasRelated: false, recordId, relatedText: '' } }];
}
cleaned = cleaned.substring(start, end + 1);

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e1) {
  try {
    parsed = JSON.parse(sanitizeJson(cleaned));
  } catch (e2) {
    return [{ json: { hasRelated: false, recordId, relatedText: '' } }];
  }
}

const related = Array.isArray(parsed.related) ? parsed.related.filter(r => r.title && r.url && r.reason) : [];

if (related.length === 0) {
  return [{ json: { hasRelated: false, recordId, relatedText: '' } }];
}

// Format as readable plain text for the Airtable multilineText field
const relatedText = related
  .map(item => '\u2022 ' + item.title + '\n  ' + item.url + '\n  Why: ' + item.reason)
  .join('\n\n');

return [{ json: { hasRelated: true, recordId, relatedText } }];

